+        for (let j = 0; j < qv.length; j++) {
+          dot += qv[j] * vec[j];
+          normA += qv[j] * qv[j];
+          normB += vec[j] * vec[j];
+        }
+        const denom = Math.sqrt(normA) * Math.sqrt(normB);
+        const sim = denom > 0 ? dot / denom : 0;
+        if (sim > 0) vectorHits.push({ docId: i, score: sim });
+      }
