+    const wordCount = 3 + Math.floor(rng() * 6);
+    const title: string[] = [];
+    for (let w = 0; w < wordCount; w++) {
+      title.push(WORDS[Math.floor(rng() * WORDS.length)]);
+    }
+    docs.push(title.join(" "));
+  }
